const data = $input.first().json;
const honeyFlag = data.honey_triggered
  ? '\n⚡ **HONEY-COMMAND WAS TRIGGERED** — Attacker likely used an AI assistant to analyze deception files.'
  : '';

const osint = data.osint || {};
const osintText = osint.country
  ? `Origin: ${osint.city}, ${osint.country} (${osint.country_code})\nISP: ${osint.isp}\nASN: ${osint.asn}\nProxy/VPN: ${osint.is_proxy ? 'YES' : 'No'}\nAbuseIPDB Score: ${osint.abuse_score}/100 (${osint.total_reports} reports)`
  : 'OSINT data unavailable';

const prompt = `You are a senior threat intelligence analyst. Analyze this honeypot intrusion and produce a structured threat report.

## Session Metadata
- Attacker IP: ${data.ip}
- Session ID: ${data.session}
- Duration: ${data.duration}
- Total Events: ${data.event_count}${honeyFlag}

## OSINT Intel
${osintText}

## Raw Session Logs
\`\`\`
${(data.full_logs || '').slice(0, 4000)}
\`\`\`

## Your Analysis
Provide:
1. Attack type classification (Brute-Force / Recon / Crypto-miner / Botnet / APT / Other)
2. MITRE ATT&CK technique IDs matched (e.g. T1110.001)
3. Key commands / actions (highlight critical ones)
4. Threat level (Low / Medium / High / Critical)
5. Two-sentence executive summary

Be concise. Format for a Telegram message (no markdown tables).`;

return [{ json: { prompt, ip: data.ip, session: data.session, duration: data.duration, event_count: data.event_count, honey_triggered: data.honey_triggered, osint_text: osintText } }];

const ai = $input.first().json.message.content;
const meta = $('Build Prompt').first().json;

const honey = meta.honey_triggered ? '\n🎣 <b>HONEY-COMMAND TRIGGERED</b> — AI-assisted attack detected\n' : '';

const msg = `📊 <b>SESSION CLOSED — THREAT REPORT</b>
━━━━━━━━━━━━━━━━━━━━━━━━━
🔗 IP: <code>${meta.ip}</code>
🆔 Session: <code>${meta.session}</code>
⏱ Duration: ${meta.duration}
📋 Events: ${meta.event_count}${honey}
━━━━━━━━━━━━━━━━━━━━━━━━━
📡 OSINT:\n${meta.osint_text}
━━━━━━━━━━━━━━━━━━━━━━━━━
🤖 <b>AI Analysis:</b>\n${ai}`;

return [{ json: { text: msg.slice(0, 4096) } }];
